import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        out.println("<html>");
        out.println("<body>");
        out.println("<h1>User Input: " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization here
        // For example, you can use OWASP Java HTML Sanitizer to sanitize HTML input
        // https://www.owasp.org/index.php/OWASP_Java_HTML_Sanitizer_Project

        // Placeholder sanitization method (replace '<' and '>' characters)
        return input.replace("<", "&lt;").replace(">", "&gt;");
    }
}

